  test("drop_fnames".fail) {
    assertCompresses(
      input = """function foo() {
            function bar() {
                return "foobar";
            }
        }""".stripMargin.trim,
      expected = """function foo() {
            function o() {
                return "foobar";
            }
        }""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // keep_fnames
