  test("keep_fnames") {
    assertCompresses(
      input = """function foo() {
            function bar() {
                return "foobar";
            }
        }""".stripMargin.trim,
      expected = """function foo() {
            function bar() {
                return "foobar";
            }
        }""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // keep_var_fnames
  // =========================================================================
  test("keep_var_fnames") {
    assertCompresses(
      input = """const foo = function () { return "barfoo" }
        const bar = () => "foobar"""".stripMargin.trim,
      expected = """const foo = function () { return "barfoo" }
        const bar = () => "foobar"""".stripMargin.trim,
      options = AllOff
    )
  }

